import numpy as np
from typing import Tuple

class PolynomialRing:
    def __init__(self, n: int, q: int):
        if n & (n - 1) != 0:
            raise ValueError("n must be a power of 2")
        self.n = n
        self.q = q

    def add(self, a: np.ndarray, b: np.ndarray) -> np.ndarray:
        return (np.array(a) + np.array(b)) % self.q

    def subtract(self, a: np.ndarray, b: np.ndarray) -> np.ndarray:
        return (np.array(a) - np.array(b)) % self.q

    def multiply(self, a: np.ndarray, b: np.ndarray) -> np.ndarray:
        a = np.array(a, dtype=np.int64)
        b = np.array(b, dtype=np.int64)
        n = self.n
        q = self.q

        # Full convolution
        result = np.zeros(2 * n - 1, dtype=np.int64)
        for i in range(n):
            for j in range(n):
                result[i + j] = (result[i + j] + a[i] * b[j]) % q

        # Reduce modulo x^n + 1: x^n ≡ -1
        reduced = np.zeros(n, dtype=np.int64)
        for i in range(2 * n - 1):
            if i < n:
                reduced[i] = (reduced[i] + result[i]) % q
            else:
                reduced[i - n] = (reduced[i - n] - result[i]) % q

        return reduced

    def scalar_multiply(self, a: np.ndarray, scalar: int) -> np.ndarray:
        return (np.array(a) * scalar) % self.q

    def negate(self, a: np.ndarray) -> np.ndarray:
        return (-np.array(a)) % self.q

    def reduce_coefficients(self, a: np.ndarray) -> np.ndarray:
        return np.array(a) % self.q

import numpy as np
from typing import List, Tuple

class ModuleLWE:
    def __init__(self, n: int, k: int, q: int, sigma: float):
        self.n = n
        self.k = k
        self.q = q
        self.sigma = sigma

    def _poly_mult(self, a: np.ndarray, b: np.ndarray) -> np.ndarray:
        a = np.array(a, dtype=np.int64)
        b = np.array(b, dtype=np.int64)
        n, q = self.n, self.q
        result = np.zeros(2 * n - 1, dtype=np.int64)
        for i in range(n):
            for j in range(n):
                result[i + j] = (result[i + j] + a[i] * b[j]) % q
        reduced = np.zeros(n, dtype=np.int64)
        for i in range(2 * n - 1):
            if i < n:
                reduced[i] = (reduced[i] + result[i]) % q
            else:
                reduced[i - n] = (reduced[i - n] - result[i]) % q
        return reduced

    def _poly_add(self, a: np.ndarray, b: np.ndarray) -> np.ndarray:
        return (np.array(a) + np.array(b)) % self.q

    def sample_matrix(self) -> List[List[np.ndarray]]:
        return [[np.random.randint(0, self.q, size=self.n) 
                 for _ in range(self.k)] for _ in range(self.k)]

    def sample_vector_small(self) -> List[np.ndarray]:
        return [np.random.randint(-1, 2, size=self.n) % self.q 
                for _ in range(self.k)]

    def sample_vector_error(self) -> List[np.ndarray]:
        return [np.round(np.random.normal(0, self.sigma, size=self.n)).astype(int) % self.q 
                for _ in range(self.k)]

    def matrix_vector_mult(self, A: List[List[np.ndarray]],
                           v: List[np.ndarray]) -> List[np.ndarray]:
        result = []
        for i in range(self.k):
            acc = np.zeros(self.n, dtype=np.int64)
            for j in range(self.k):
                prod = self._poly_mult(A[i][j], v[j])
                acc = self._poly_add(acc, prod)
            result.append(acc)
        return result

    def vector_add(self, a: List[np.ndarray], b: List[np.ndarray]) -> List[np.ndarray]:
        return [self._poly_add(a[i], b[i]) for i in range(self.k)]

    def keygen(self) -> Tuple[Tuple[List[List[np.ndarray]], List[np.ndarray]],
                               List[np.ndarray]]:
        A = self.sample_matrix()
        s = self.sample_vector_small()
        e = self.sample_vector_error()
        As = self.matrix_vector_mult(A, s)
        t = self.vector_add(As, e)
        return (A, t), s

    def compute_sizes(self) -> dict:
        bits_per_coeff = int(np.ceil(np.log2(self.q)))

        # A: k×k polynomials of degree n
        matrix_bits = self.k * self.k * self.n * bits_per_coeff

        # t: k polynomials
        vector_bits = self.k * self.n * bits_per_coeff

        pk_bytes = (matrix_bits + vector_bits) // 8
        sk_bytes = self.k * self.n  # small coefficients

        return {
            'pk_bytes': pk_bytes,
            'sk_bytes': sk_bytes,
            'effective_dimension': self.n * self.k,
            'security_estimate_bits': int(0.265 * self.n * self.k)
        }
